1	const PROCESSING_FEE = 5;
2	const COMPONENT_UNIT_PRICE = 25;
3	const COMPONENT_BLOCK_PRICE = 60;
4	const COMPONENT_BLOCK_SIZE = 3;
5	
6	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	  staff: 800,
17	  potion: 400,
18	};
19	const COMPONENT_INSURANCE_VALUE = 250;
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const FIRST_INSURANCE_RATE = 0.1;
24	const CURSE_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	const LOYALTY_DISCOUNT_RATE = 0.2;
28	const LOYALTY_YEARS_THRESHOLD = 2;
29	const FOLLOWUP_CONTRACT_DISCOUNT_RATE = 0.15;
30	
31	const CLAIM_DEDUCTIBLE = 100;
32	const CAP_MULTIPLIER = 2;
33	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
34	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
35	const DRAGON_MATERIAL = "dragon";
36	
37	type Item = {
38	  type: string;
39	  material?: string;
40	  enchantment?: number;
41	  cursed?: boolean;
42	};
43	type Customer = { yearsWithMHPCO: number };
44	type QuoteStep = { op: "quote"; items: Item[] };
45	type Damage = { itemType: string; amount: number };
46	type Incident = { cause: string; damages: Damage[] };
47	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
48	type Step = QuoteStep | ClaimStep;
49	type Scenario = { customer: Customer; steps: Step[] };
50	type QuoteResult = { premium: number };
51	type ClaimResult = { payout: number; remainingCap: number };
52	type StepResult = QuoteResult | ClaimResult;
53	
54	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
55	
56	const basePremiumForRegularItem = (item: Item): number =>
57	  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
58	
59	const insuranceValueForItem = (item: Item): number =>
60	  isComponent(item)
61	    ? COMPONENT_INSURANCE_VALUE
62	    : INSURANCE_VALUE_BY_ITEM_TYPE[item.type] ?? 0;
63	
64	const itemSurcharges = (item: Item): number => {
65	  const base = basePremiumForRegularItem(item);
66	  let surcharge = 0;
67	  if (item.cursed) surcharge += base * CURSE_SURCHARGE_RATE;
68	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
69	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
70	  }
71	  return surcharge;
72	};
73	
74	const partition = <T,>(items: T[], predicate: (item: T) => boolean): [T[], T[]] =>
75	  items.reduce<[T[], T[]]>(
76	    ([yes, no], item) => (predicate(item) ? [[...yes, item], no] : [yes, [...no, item]]),
77	    [[], []],
78	  );
79	
80	const countByType = (items: Item[]): Record<string, number> =>
81	  items.reduce<Record<string, number>>((acc, item) => {
82	    acc[item.type] = (acc[item.type] ?? 0) + 1;
83	    return acc;
84	  }, {});
85	
86	const componentGroupPremium = (count: number): number =>
87	  count === COMPONENT_BLOCK_SIZE
88	    ? COMPONENT_BLOCK_PRICE
89	    : count * COMPONENT_UNIT_PRICE;
90	
91	const sumRegularItemBasePremiums = (items: Item[]): number =>
92	  items.reduce((total, item) => total + basePremiumForRegularItem(item), 0);
93	
94	const sumComponentPremiums = (components: Item[]): number =>
95	  Object.values(countByType(components)).reduce(
96	    (sum, count) => sum + componentGroupPremium(count),
97	    0,
98	  );
99	
100	const policyBasePremium = (items: Item[]): number => {
101	  const [components, regularItems] = partition(items, isComponent);
102	  return sumRegularItemBasePremiums(regularItems) + sumComponentPremiums(components);
103	};
104	
105	const sumItemSurcharges = (items: Item[]): number =>
106	  items.reduce((total, item) => total + itemSurcharges(item), 0);
107	
108	type QuoteContext = {
109	  customer: Customer;
110	  contractIndex: number;
111	};
112	
113	const policyModifierRate = (ctx: QuoteContext): number => {
114	  let rate = FIRST_INSURANCE_RATE;
115	  if (ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) rate -= LOYALTY_DISCOUNT_RATE;
116	  if (ctx.contractIndex >= 1) rate -= FOLLOWUP_CONTRACT_DISCOUNT_RATE;
117	  return rate;
118	};
119	
120	const premiumForItems = (items: Item[], ctx: QuoteContext): number => {
121	  const policyBase = policyBasePremium(items);
122	  const surcharges = sumItemSurcharges(items);
123	  const policyModifiers = policyBase * policyModifierRate(ctx);
124	  return Math.ceil(policyBase + surcharges + policyModifiers + PROCESSING_FEE);
125	};
126	
127	const quote = (step: QuoteStep, ctx: QuoteContext): QuoteResult => ({
128	  premium: premiumForItems(step.items, ctx),
129	});
130	
131	type Policy = {
132	  items: Item[];
133	  remainingCap: number;
134	};
135	
136	const buildPolicy = (items: Item[]): Policy => ({
137	  items,
138	  remainingCap: items.reduce((sum, item) => sum + insuranceValueForItem(item), 0) * CAP_MULTIPLIER,
139	});
140	
141	const reimbursementForDamage = (item: Item, amount: number): number => {
142	  if (item.material === DRAGON_MATERIAL) {
143	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD) {
144	      return amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
145	    }
146	    return amount;
147	  }
148	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD) {
149	    return amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
150	  }
151	  return amount;
152	};
153	
154	const payoutForDamage = (item: Item, amount: number): number => {
155	  const reimbursement = reimbursementForDamage(item, amount);
156	  return Math.max(0, reimbursement - CLAIM_DEDUCTIBLE);
157	};
158	
159	const findItemForDamage = (policy: Policy, damage: Damage): Item | undefined =>
160	  policy.items.find((item) => item.type === damage.itemType);
161	
162	const processClaim = (step: ClaimStep, policy: Policy): ClaimResult => {
163	  let totalPayout = 0;
164	  for (const damage of step.incident.damages) {
165	    const item = findItemForDamage(policy, damage);
166	    if (!item) continue;
167	    const wanted = Math.floor(payoutForDamage(item, damage.amount));
168	    const actualPayout = Math.min(wanted, policy.remainingCap);
169	    totalPayout += actualPayout;
170	    policy.remainingCap -= actualPayout;
171	  }
172	  return { payout: totalPayout, remainingCap: policy.remainingCap };
173	};
174	
175	export const processScenario = (input: Scenario): { results: StepResult[] } => {
176	  let contractIndex = 0;
177	  const policies: Record<number, Policy> = {};
178	  const results: StepResult[] = input.steps.map((step, idx) => {
179	    if (step.op === "quote") {
180	      const ctx: QuoteContext = { customer: input.customer, contractIndex };
181	      contractIndex += 1;
182	      policies[idx] = buildPolicy(step.items);
183	      return quote(step, ctx);
184	    }
185	    const policy = policies[step.policy];
186	    return processClaim(step, policy);
187	  });
188	  return { results };
189	};
